#!/bin/bash
#
# build_installer.sh
# Builds a macOS .pkg installer for the Logic Pro X Steinberg CC121 MIDI controller script.
#
# Usage:
#   chmod +x build_installer.sh
#   ./build_installer.sh
#
# Requires: macOS with pkgbuild and productbuild (included with Xcode Command Line Tools)
#
# Output: SteinbergCC121.pkg in the current directory
#

set -euo pipefail

# --- Paths -------------------------------------------------------------------

DEVICE_NAME="Steinberg CC121.device"
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
BUILD_DIR="$SCRIPT_DIR/build"
PAYLOAD_DIR="$BUILD_DIR/payload"
SCRIPTS_DIR="$BUILD_DIR/scripts"
RESOURCES_DIR="$BUILD_DIR/resources"
COMPONENT_PKG="$BUILD_DIR/cc121-component.pkg"


# --- Set version ---------------------------------------------------------------

# Read integer version from config.lua (e.g. 90, 105, 200)
RAW_VERSION=$(grep -m1 '^VERSION' "$SCRIPT_DIR/$DEVICE_NAME/config.lua" | sed 's/[^0-9]//g')
if [ -z "$RAW_VERSION" ]; then
    echo "ERROR: Could not read VERSION from config.lua"
    exit 1
fi

# Convert integer to semantic version: 90 → 0.9.0, 105 → 1.0.5, 1200 → 12.0.0
MAJOR=$((RAW_VERSION / 100))
MINOR=$(( (RAW_VERSION % 100) / 10 ))
PATCH=$((RAW_VERSION % 10))
VERSION="${MAJOR}.${MINOR}.${PATCH}"

echo "==> Version: $VERSION (from VERSION=$RAW_VERSION)"

# --- Configuration -----------------------------------------------------------

PRODUCT_NAME="Steinberg CC121 for Logic Pro"
PACKAGE_ID="ee.kit.cc121.logicpro"
OUTPUT_PKG="LogicSteinbergCC121.pkg"

# Logic Pro MIDI Device Scripts install location
# The folder structure is: /Library/Audio/MIDI Device Scripts/<Manufacturer>/<Device>/
INSTALL_DIR="/Library/Audio/MIDI Device Scripts/Yamaha/$DEVICE_NAME/"

# --- Clean & prepare --------------------------------------------------------

echo "==> Cleaning build directory..."
rm -rf "$BUILD_DIR"
mkdir -p "$PAYLOAD_DIR" "$SCRIPTS_DIR" "$RESOURCES_DIR"

# --- Stage payload -----------------------------------------------------------
# Recreate the target directory structure under payload/
# Files placed here will be installed to $INSTALL_DIR

echo "==> Staging payload..."
PAYLOAD_INSTALL_DIR="$PAYLOAD_DIR$INSTALL_DIR"
mkdir -p "$PAYLOAD_INSTALL_DIR"

# Copy the Lua config script
cp "$SCRIPT_DIR/$DEVICE_NAME/config.lua" "$PAYLOAD_INSTALL_DIR/config.lua"

# Copy optional device icon (256x256 PNG) if present
if [ -f "$SCRIPT_DIR/$DEVICE_NAME/icon.png" ]; then
    cp "$SCRIPT_DIR/$DEVICE_NAME/icon.png" "$PAYLOAD_INSTALL_DIR/icon.png"
    echo "    Included icon.png"
fi

# Copy any additional resource files (images, etc.) if present
for f in "$SCRIPT_DIR/$DEVICE_NAME"/*.lua; do
    [ -f "$f" ] || continue
    fname="$(basename "$f")"
    if [ "$fname" != "config.lua" ]; then
        cp "$f" "$PAYLOAD_INSTALL_DIR/$fname"
        echo "    Included $fname"
    fi
done

echo "    Payload staged at: $INSTALL_DIR"

# --- Create postinstall script -----------------------------------------------
# This ensures correct ownership and permissions after installation.

echo "==> Creating installer scripts..."
cat > "$SCRIPTS_DIR/postinstall" << 'POSTINSTALL'
#!/bin/bash
DEVICE_NAME="Steinberg CC121.device"
INSTALL_DIR="/Library/Audio/MIDI Device Scripts/Yamaha/"

# Ensure correct ownership and permissions
chmod -R 755 "$INSTALL_DIR"
chmod 644 "$INSTALL_DIR/$DEVICE_NAME/config.lua"
[ -f "$INSTALL_DIR/$DEVICE_NAME/icon.png" ] && chmod 644 "$INSTALL_DIR/$DEVICE_NAME/icon.png"

exit 0
POSTINSTALL
chmod +x "$SCRIPTS_DIR/postinstall"

# --- Create welcome HTML for the installer UI --------------------------------

echo "==> Creating installer resources..."
cat > "$RESOURCES_DIR/welcome.html" << 'WELCOME'
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Steinberg CC121 for Logic Pro</title>
<style>
    body { font-family: -apple-system, "Helvetica Neue", Helvetica, sans-serif; font-size: 13px; line-height: 1.5; color: #333; }
    h1 { font-size: 18px; margin-bottom: 0.5em; }
    h2 { font-size: 14px; margin-top: 1.2em; margin-bottom: 0.3em; }
    ul { padding-left: 1.5em; }
    .path { font-family: Menlo, monospace; font-size: 11px; padding: 2px 5px; border-radius: 3px; }

</style>
</head>
<body>
<h1>Steinberg CC121 for Logic Pro</h1>
<p>This installer will set up the Steinberg CC121 MIDI controller for Logic Pro.</p>

<img
     src="data:image/png;base64,"
     alt="Steinberg CC121 MIDI controller" width="256" height="182" />

<h2>After installation</h2>
<ol>
    <li>Connect your CC121 via USB.</li>
    <li>Open Logic Pro — the CC121 should be detected automatically.</li>
    <li>If prompted, click <strong>Auto Assign</strong> to activate the controller.</li>
    <li>The "Cubase Ready" LED on the CC121 will turn solid, confirming the connection.</li>
</ol>

</body>
</html>
WELCOME

# --- Create license file (optional — remove this block if not needed) --------

if [ -f "$SCRIPT_DIR/$DEVICE_NAME/LICENSE" ]; then
    cp "$SCRIPT_DIR/$DEVICE_NAME/LICENSE" "$RESOURCES_DIR/LICENSE.txt"
    echo "    Included LICENSE"
fi

# --- Build component package with pkgbuild -----------------------------------

echo "==> Building component package..."
pkgbuild \
    --root "$PAYLOAD_DIR" \
    --scripts "$SCRIPTS_DIR" \
    --identifier "$PACKAGE_ID" \
    --version "$VERSION" \
    --install-location "/" \
    "$COMPONENT_PKG"

# --- Create distribution XML for productbuild --------------------------------

echo "==> Creating distribution file..."
cat > "$BUILD_DIR/distribution.xml" << DIST
<?xml version="1.0" encoding="utf-8"?>
<installer-gui-script minSpecVersion="2">
    <title>${PRODUCT_NAME}</title>
    <welcome file="welcome.html" mime-type="text/html"/>
    $([ -f "$RESOURCES_DIR/LICENSE.txt" ] && echo '<license file="LICENSE.txt" mime-type="text/plain"/>' || echo '')
    <options customize="never" require-scripts="false" hostArchitectures="x86_64,arm64"/>
    <domains enable_localSystem="true"/>
    <choices-outline>
        <line choice="default">
            <line choice="cc121"/>
        </line>
    </choices-outline>
    <choice id="default"/>
    <choice id="cc121" visible="false" title="CC121 Controller Script">
        <pkg-ref id="${PACKAGE_ID}"/>
    </choice>
    <pkg-ref id="${PACKAGE_ID}" version="${VERSION}" onConclusion="none">cc121-component.pkg</pkg-ref>
</installer-gui-script>
DIST

# --- Build final product archive with productbuild ----------------------------

echo "==> Building installer package..."
productbuild \
    --distribution "$BUILD_DIR/distribution.xml" \
    --resources "$RESOURCES_DIR" \
    --package-path "$BUILD_DIR" \
    "$SCRIPT_DIR/$OUTPUT_PKG"

echo ""
echo "==> Done! Installer created: $OUTPUT_PKG"
echo ""
echo "    To install:  Double-click $OUTPUT_PKG"
echo "    Install path: $INSTALL_DIR"
echo ""
echo "    Optional: sign the package for Gatekeeper:"
echo "    productsign --sign 'Developer ID Installer: Your Name' $OUTPUT_PKG ${OUTPUT_PKG%.pkg}-signed.pkg"
echo ""

# --- Clean up build artifacts ------------------------------------------------

rm -rf "$BUILD_DIR"
echo "==> Build directory cleaned."
